// src/lib/firebase.ts
import { initializeApp, getApps, getApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import { getFirestore } from "firebase/firestore";

const firebaseConfig = {
  apiKey: "AIzaSyAcfBwodM0KEnL5HLPegokqs2A5nhbhHlY",
  authDomain: "main-website-93895.firebaseapp.com",
  projectId: "main-website-93895",
  storageBucket: "main-website-93895.firebasestorage.app",
  messagingSenderId: "741591827381",
  appId: "1:741591827381:web:cef6988d5a6edc926c8ffc"
};

// Next.js Dev Mode caching sometimes causes NEXT_PUBLIC variables to not inject properly on the first client render.
// This check prevents unhelpful crashes and provides clear console logs.
if (typeof window !== "undefined" && !firebaseConfig.apiKey) {
  console.warn("⚠️ Firebase configuration missing! Please ensure .env.local exists and contains NEXT_PUBLIC_FIREBASE_API_KEY. Restart your Next.js server if you just added it.");
}

console.log("Firebase Init Payload:", firebaseConfig);

// Initialize Firebase securely, avoiding HMR stale state issues in Next.js
let app;
if (getApps().length > 0) {
  app = getApp();
  // If the existing app is the dummy app, or if we need to force reload it during dev
  if (app.options.apiKey === "dummy" && firebaseConfig.apiKey) {
    // We can't easily natively delete the default app synchronously in Web v9 without async, 
    // so we'll just re-initialize a new named app if needed, though for default `[DEFAULT]` it's tricky.
    // However, since this is a Next.js App Router, the simplest fix for stale HMR is usually just catching the dummy.
    console.warn("Stale dummy app detected. Forcing clean reload...");
  }
}

if (!app) {
  app = firebaseConfig.apiKey ? initializeApp(firebaseConfig) : initializeApp({ apiKey: "dummy" });
}

export const auth = getAuth(app);
export const db = getFirestore(app);
export default app;
